  @protected
  void sse_encode_agent_request(AgentRequest self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case AgentRequest_ListKeys(requestId: final requestId):
        sse_encode_i_32(0, serializer);
        sse_encode_String(requestId, serializer);
      case AgentRequest_Sign(
        requestId: final requestId,
        fingerprint: final fingerprint,
        description: final description,
        deviceLabel: final deviceLabel,
        deviceId: final deviceId,
      ):
        sse_encode_i_32(1, serializer);
        sse_encode_String(requestId, serializer);
        sse_encode_String(fingerprint, serializer);
        sse_encode_String(description, serializer);
        sse_encode_String(deviceLabel, serializer);
        sse_encode_String(deviceId, serializer);
    }
  }

  @protected
  void sse_encode_app_message(AppMessage self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case AppMessage_AgentEvent(event: final event):
        sse_encode_i_32(0, serializer);
        sse_encode_box_autoadd_agent_request(event, serializer);
      case AppMessage_BusEvent(event: final event):
        sse_encode_i_32(1, serializer);
        sse_encode_box_autoadd_bus_csr_event(event, serializer);
      case AppMessage_SessionLockRequired():
        sse_encode_i_32(2, serializer);
    }
  }

