    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case MxVerifyEvent_Waiting():
        sse_encode_i_32(0, serializer);
      case MxVerifyEvent_RequestReceived():
        sse_encode_i_32(1, serializer);
      case MxVerifyEvent_Emojis(emojis: final emojis):
        sse_encode_i_32(2, serializer);
        sse_encode_list_mx_emoji_info(emojis, serializer);
      case MxVerifyEvent_Done():
        sse_encode_i_32(3, serializer);
      case MxVerifyEvent_Cancelled(reason: final reason):
        sse_encode_i_32(4, serializer);
        sse_encode_String(reason, serializer);
    }
  }

